#include <iostream>
#include <vector>
using namespace std;

template<typename T>
class Vector {
    vector<T> data;

public:
    Vector(size_t size = 0) : data(size) {}
    Vector(const vector<T>& values) : data(values) {}

    size_t size() const { return data.size(); }

    T& operator[](size_t i) { return data[i]; }
    const T& operator[](size_t i) const { return data[i]; }

    template<typename Expr>
    Vector& operator=(const Expr& expr) {
        data.resize(expr.size());
        for (size_t i = 0; i < data.size(); ++i) {
            data[i] = expr[i];
        }
        return *this;
    }
};

template<typename Left, typename Right>
class VectorAdd {
    const Left& left;
    const Right& right;

public:
    VectorAdd(const Left& l, const Right& r) : left(l), right(r) {}

    size_t size() const { return left.size(); }

    auto operator[](size_t i) const -> decltype(left[i] + right[i]) {
        return left[i] + right[i];
    }
};

template<typename Left, typename Right>
VectorAdd<Left, Right> operator+(const Left& left, const Right& right) {
    return VectorAdd<Left, Right>(left, right);
}

int main() {
    Vector<double> a({1.0, 2.0, 3.0});
    Vector<double> b({4.0, 5.0, 6.0});
    Vector<double> c({7.0, 8.0, 9.0});
    Vector<double> result(3);

    result = a + b + c;

    cout << \Результат: ";
    for (size_t i = 0; i < result.size(); ++i) {
        cout << result[i] << " ";
    }
    cout << endl;

    return 0;
}"

#include <iostream>
#include <coroutine>
#include <memory>
using namespace std;

template<typename T>
struct Generator {
    struct promise_type {
        T value;

        Generator get_return_object() {
            return Generator{handle_type::from_promise(*this)};
        }

        suspend_always initial_suspend() { return {}; }
        suspend_always final_suspend() noexcept { return {}; }

        void unhandled_exception() { terminate(); }

        suspend_always yield_value(T val) {
            value = val;
            return {};
        }

        void return_void() {}
    };

    using handle_type = coroutine_handle<promise_type>;

    handle_type coro;

    Generator(handle_type h) : coro(h) {}
    ~Generator() {
        if (coro) coro.destroy();
    }

    T value() {
        return coro.promise().value;
    }

    bool next() {
        if (!coro.done()) {
            coro.resume();
            return !coro.done();
        }
        return false;
    }
};

Generator<int> fibonacci(int n) {
    int a = 0, b = 1;

    for (int i = 0; i < n; ++i) {
        co_yield a;
        int next = a + b;
        a = b;
        b = next;
    }
}

int main() {
    auto fib_gen = fibonacci(10);

    cout << \Числа Фибоначчи: ";
    while (fib_gen.next()) {
        cout << fib_gen.value() << " ";
    }
    cout << endl;

    return 0;
}"

