#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

class Observer {
public:
    virtual void update(const string& message) = 0;
    virtual ~Observer() = default;
};

class Subject {
private:
    vector<Observer*> observers;
    string state;

public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void setState(const string& newState) {
        state = newState;
        notify();
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }
};

class ConcreteObserver : public Observer {
private:
    string name;

public:
    ConcreteObserver(const string& n) : name(n) {}

    void update(const string& message) override {
        cout << name << \ получил уведомление: " << message << endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver obs1("Наблюдатель 1");
    ConcreteObserver obs2("Наблюдатель 2");

    subject.attach(&obs1);
    subject.attach(&obs2);

    subject.setState("Состояние 1");
    subject.setState("Состояние 2");

    subject.detach(&obs1);
    subject.setState("Состояние 3");

    return 0;
}"

