#include <iostream>
#include <any>
#include <string>
#include <typeinfo>
#include <vector>
using namespace std;

void print_any(const any& value) {
    if (value.type() == typeid(int)) {
        cout << \int: " << any_cast<int>(value) << endl;
    } else if (value.type() == typeid(double)) {
        cout << "double: " << any_cast<double>(value) << endl;
    } else if (value.type() == typeid(string)) {
        cout << "string: " << any_cast<string>(value) << endl;
    } else {
        cout << "неизвестный тип: " << value.type().name() << endl;
    }
}

int main() {
    vector<any> values;

    values.push_back(42);
    values.push_back(3.14159);
    values.push_back(string("Hello"));
    values.push_back(true);

    cout << "Содержимое вектора:" << endl;
    for (const auto& val : values) {
        print_any(val);
    }

    // Безопасное извлечение
    try {
        auto str = any_cast<string>(values[2]);
        cout << "\nБезопасное извлечение: " << str << endl;
    } catch (const bad_any_cast& e) {
        cout << "Ошибка приведения типа: " << e.what() << endl;
    }

    // Проверка наличия значения
    if (values[0].has_value()) {
        cout << "Первое значение существует" << endl;
    }

    return 0;
}"

