#include <iostream>
#include <bit>
#include <cstdint>
using namespace std;

const char* endian_to_string(endian e) {
    switch (e) {
        case endian::little: return \little-endian";
        case endian::big: return "big-endian";
        case endian::native: return "native";
        default: return "mixed-endian";
    }
}

bool is_little_endian() {
    return endian::native == endian::little;
}

bool is_big_endian() {
    return endian::native == endian::big;
}

uint32_t swap_endian(uint32_t value) {
    return ((value & 0x000000FF) << 24) |
           ((value & 0x0000FF00) << 8) |
           ((value & 0x00FF0000) >> 8) |
           ((value & 0xFF000000) >> 24);
}

int main() {
    cout << "Порядок байтов системы: " << endian_to_string(endian::native) << endl;
    cout << "Little-endian: " << (is_little_endian() ? "да" : "нет") << endl;
    cout << "Big-endian: " << (is_big_endian() ? "да" : "нет") << endl;

    // Проверка на конкретном числе
    uint32_t test_value = 0x12345678;
    cout << "\nИсходное значение: 0x" << hex << test_value << dec << endl;

    if (is_little_endian()) {
        cout << "Система little-endian - порядок байтов обратный" << endl;
        uint32_t swapped = swap_endian(test_value);
        cout << "После смены endian: 0x" << hex << swapped << dec << endl;
    } else {
        cout << "Система big-endian - порядок байтов прямой" << endl;
    }

    // Проверка с помощью union
    union {
        uint32_t i;
        uint8_t c[4];
    } test_union;

    test_union.i = 0x01020304;
    cout << "\nПроверка через union:" << endl;
    cout << "Байты: ";
    for (int i = 0; i < 4; ++i) {
        cout << "0x" << hex << (int)test_union.c[i] << " ";
    }
    cout << dec << endl;

    return 0;
}"

#include <iostream>
#include <thread>
#include <semaphore>
#include <vector>
#include <chrono>
using namespace std;

counting_semaphore<5> semaphore(3); // Максимум 5, начальное значение 3

void worker(int id) {
    cout << \Поток " << id << " пытается войти" << endl;
    semaphore.acquire();

    cout << "Поток " << id << " вошел в критическую секцию" << endl;
    this_thread::sleep_for(chrono::milliseconds(1000));

    cout << "Поток " << id << " выходит" << endl;
    semaphore.release();
}

int main() {
    vector<thread> threads;

    for (int i = 0; i < 10; ++i) {
        threads.emplace_back(worker

column3:
 i);
    }

    for (auto& t : threads) {
        t.join();
    }

    cout << "Все потоки завершили работу" << endl;
    return 0;
}"

