#include <iostream>
#include <thread>
#include <barrier>
#include <vector>
#include <chrono>
using namespace std;

barrier sync_point(3, []() noexcept {
    cout << \Все потоки достигли барьера!" << endl;
});

void worker(int id) {
    cout << "Поток " << id << " начал фазу 1" << endl;
    this_thread::sleep_for(chrono::milliseconds(100 * id));

    sync_point.arrive_and_wait();

    cout << "Поток " << id << " начал фазу 2" << endl;
    this_thread::sleep_for(chrono::milliseconds(50 * id));

    sync_point.arrive_and_wait();

    cout << "Поток " << id << " завершил работу" << endl;
}

int main() {
    vector<thread> threads;

    for (int i = 0; i < 3; ++i) {
        threads.emplace_back(worker

column3:
 i);
    }

    for (auto& t : threads) {
        t.join();
    }

    cout << "Все потоки завершили работу" << endl;
    return 0;
}"
